mapper.sql:
where eo.tenant_id = #{tenantId}
  and eo.del_flag = 0

  and eo.handle_status = #{statusCode}


  and (
    eo.exception_no like concat('%', #{keyword}, '%')
    or eo.related_order_no like concat('%', #{keyword}, '%')
    or eo.exception_type like concat('%', #{keyword}, '%')
    or eo.handle_status like concat('%', #{keyword}, '%')
  )

mapper.select:

from payment_exception_order eo

order by eo.created_at desc
limit #{limit} offset #{offset}


from payment_exception_order eo
where eo.tenant_id = #{tenantId}
  and eo.id = #{id}
  and eo.del_flag = 0
limit 1

select *
from payment_exception_order
where tenant_id = #{tenantId}
  and related_order_no = #{relatedOrderNo}
  and exception_type = #{exceptionType}
  and del_flag = 0
limit 1
